$$, $$41b38142b14fef28dac6e1748cea18cf3a0c7fefdb7dfcdcaa428dc77afd4aea$$, $${"A": "60cf14cb201dc5a3ba60f599f1b9b782e85165ae06d9da4f6888f3ef1db551be", "D": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "E": "34269dbcc625a0e6bf5ce9e5cd1e26323c291bd68f07d3ef27865e77cb2738fa"}$$::jsonb, $$Budget J-Books/FY26/USAF/FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, 937, $$2026-05-07T23:57:02.622579+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0901220F$$, 2026, $$The Force Development Transformation program contains two independent DAF initiatives addressing vital personnel issues: Personnel Services Delivery and the Total
Integration Mobilization Execution System.

 Personnel Services Delivery:
 Personnel Services Delivery (PSD), under the Personnel Administration program, funds operational developments necessary to acquire, field, and modify business
 processes to transform the delivery of Human Resources (HR) capabilities through the structured redesign of the Total Force Personnel Community's people (Active
 Duty, Reserve, Guard, and Civilians), processes, and technologies. PSD Transformation fundamentally shifts the way personnel services are provided, transitioning
 from primarily face-to-face interactions with a personalist to a tiered model with services delivered through online self-service, contact centers, and reduced in-person
 interactions. PSD supports the migration of legacy applications and other information technologies from on premises data centers to a more sustainable cloud-based
 hosting solution and flexible services-based architecture as defined by the Defense Enterprise Service Management Framework (DESMF). In addition, funds will be
 used to perform studies and innovative integration efforts for common technology capabilities such as cloud migration, technology development, and mobile application.
 The FY 2026 request for PSD includes 1,735 thousand of discretionary and 0 thousand of mandatory (reconciliation) for a total of 1,735 thousand. The mandatory funds
 procure an additional 0 PSD systems in FY 2026. Further information for this reconciliation request is provided in Chapter 5 of the Reconciliation Exhibit.

 Total Integration Mobilization Execution System:
 The Total Integrated Mobilization Execution System is the Department of the Air Force's cloud-based system of record to mobilize Air Reserve Component (ARC) forces
 to perform operational and institutional missions in support of the active component. TIMES collects and prioritizes global ARC utilization requirements, generates
 mobilization authorizations, and automates and synchronizes the ARC utilization process to rapidly generate capability, increase lethality, and enable predictive analytics
 and data-driven decision making. The Air Force cannot execute the Secretary of Defense's national security priorities without mobilizing the forces and capabilities in the
 ARC. Approximately 35-40% of the Combatant Command requirements that are tasked to the Air Force are filled by ARC forces.

 This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability; The use of such programs
