$$, $$c56cfb8f747c7fc9d85bf7797680634612b9fdb338033ff4daed45dfc22dcd19$$, $${"A": "03220840f48b42221aee1ffe855fa2ca918c689d339d9aaeeb370d3e8cb26a82", "C": "a047e5c953b10f8d4ba34d4bc19e0b43fb35fbe2b3b2d22ffb1ee75279ba5152", "D": "bb00404da6f41c40aeea509e7876ef4ff20d467d1c194917e973e6944cadad5f"}$$::jsonb, $$Budget J-Books/FY26/USAF/FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, 971, $$2026-05-07T23:57:02.622579+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0601103SF$$, 2026, $$This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technology
superiority. Research topics include, but are not limited to, revolutionary and high priority technologies critical to the five core technical competencies of the United
States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness. The program also
enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies.
This program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A
fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and
interdisciplinary efforts. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to
harmonize efforts and eliminate duplication.

 This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi domain science and technology (S&T) solutions that
 propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the
 Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T.

 In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support
 the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc.

 Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain
 research with space-domain application.

 The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the
 workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget.

 This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental
 knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs.

