INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$1203622SF$$, 2026, $$This Program Element (PE) 1203622, Space Warfighting Analysis Center (SWAC) funds increased scope towards capability area analyses and integration, modeling,
integrated modeling & analysis, and experimentation to create operational concepts and force design guidance for existing and emerging USSF missions. Capability
Area design analyses identify the integrated suite of operational capabilities that fulfills USSF imperatives to preserve the United States' freedom of action in space;
enables Joint Force lethality and effectiveness; and provides the Service options for developing capabilities operating in, from, and to space. These analyses efforts
team with relevant stakeholders across the National Security Space enterprise from an independent perspective and will provide analytic insight to the Service to inform
and/or validate solutions to operational needs and provide a basis for future capability development programs. USSF force design analyses are organized into three
main focus areas: Multi-Domain Sensing, Spectrum Warfare, and Force Design Integration which are aligned to USSF priorities, and follow a disciplined approach to
discover, analyze, and validate concepts and the associated family of systems required to satisfy current/future mission needs while including comprehensive threat
analysis. The resulting force design products will help define and inform future USSF mission requirements, capabilities/architectures, priorities, funding needs, and
interface standards.

 This program element may include necessary emergent/unanticipated civilian pay expenses required to manage and execute the force design mission assigned to the
 SWAC and/or deliver products for evolving weapon system capabilities.

